import type { FC } from 'react';
import Alert from '@mui/material/Alert';
import FormControl from '@mui/material/FormControl';
import FormHelperText from '@mui/material/FormHelperText';
import InputLabel from '@mui/material/InputLabel';
import MenuItem from '@mui/material/MenuItem';
import Select from '@mui/material/Select';
import Stack from '@mui/material/Stack';
import TextField from '@mui/material/TextField';
import Typography from '@mui/material/Typography';
import { SELECT_MENU_PROPS } from '../shared/selectMenuProps';

interface ToolWizardBasicsStepProps {
  name: string;
  setName: (v: string) => void;
  namespace: string;
  setNamespace: (v: string) => void;
  description: string;
  setDescription: (v: string) => void;
  protocol: string;
  setProtocol: (v: string) => void;
  framework: string;
  setFramework: (v: string) => void;
  nameError: string | undefined;
  nameWarning: string | undefined;
  availableNamespaces: string[];
}

export const ToolWizardBasicsStep: FC<ToolWizardBasicsStepProps> = ({
  name,
  setName,
  namespace,
  setNamespace,
  description,
  setDescription,
  protocol,
  setProtocol,
  framework,
  setFramework,
  nameError,
  nameWarning,
  availableNamespaces,
}) => (
  <Stack spacing={2}>
    <Typography variant="body2" color="text.secondary" sx={{ mb: 0.5 }}>
      Define the identity of your MCP tool. The name and namespace determine
      where it runs on the cluster.
    </Typography>
    <TextField
      label="Name"
      value={name}
      onChange={e => setName(e.target.value)}
      fullWidth
      required
      size="small"
      error={!!nameError}
      helperText={
        nameError ?? 'Lowercase alphanumeric and hyphens (max 63 chars).'
      }
      placeholder="my-weather-tool"
    />
    {nameWarning && !nameError && (
      <Alert severity="warning" variant="outlined" sx={{ py: 0.25 }}>
        <Typography variant="caption">{nameWarning}</Typography>
      </Alert>
    )}
    {availableNamespaces.length > 0 ? (
      <FormControl size="small" fullWidth required>
        <InputLabel>Namespace</InputLabel>
        <Select
          label="Namespace"
          value={namespace}
          onChange={e => setNamespace(e.target.value)}
          MenuProps={SELECT_MENU_PROPS}
        >
          {availableNamespaces.map(ns => (
            <MenuItem key={ns} value={ns}>
              {ns}
            </MenuItem>
          ))}
        </Select>
      </FormControl>
    ) : (
      <TextField
        label="Namespace"
        value={namespace}
        onChange={e => setNamespace(e.target.value)}
        fullWidth
        required
        size="small"
        helperText="Target Kubernetes namespace for the tool."
      />
    )}
    <TextField
      label="Description"
      value={description}
      onChange={e => setDescription(e.target.value)}
      fullWidth
      multiline
      minRows={2}
      size="small"
      helperText="Brief description of what this tool does."
      placeholder="e.g. Weather lookup via Open-Meteo API"
    />
    <FormControl size="small" fullWidth>
      <InputLabel>Protocol</InputLabel>
      <Select
        label="Protocol"
        value={protocol}
        onChange={e => setProtocol(e.target.value)}
        MenuProps={SELECT_MENU_PROPS}
      >
        <MenuItem value="streamable_http">Streamable HTTP</MenuItem>
        <MenuItem value="mcp">MCP</MenuItem>
        <MenuItem value="http">HTTP</MenuItem>
        <MenuItem value="grpc">gRPC</MenuItem>
      </Select>
      <FormHelperText>
        Transport protocol for the tool endpoint. Streamable HTTP is recommended
        for most MCP tools.
      </FormHelperText>
    </FormControl>
    <FormControl size="small" fullWidth>
      <InputLabel>Framework</InputLabel>
      <Select
        label="Framework"
        value={framework}
        onChange={e => setFramework(e.target.value)}
        MenuProps={SELECT_MENU_PROPS}
      >
        <MenuItem value="Python">Python</MenuItem>
        <MenuItem value="nodejs">Node.js</MenuItem>
        <MenuItem value="">Other</MenuItem>
      </Select>
      <FormHelperText>
        Runtime language. Sets a label on the deployment — does not affect the
        container itself.
      </FormHelperText>
    </FormControl>
  </Stack>
);
