import Box from '@mui/material/Box';
import Typography from '@mui/material/Typography';
import Button from '@mui/material/Button';
import Snackbar from '@mui/material/Snackbar';
import AddIcon from '@mui/icons-material/Add';
import { AdminSection } from '../shared/AdminSection';
import type { McpServer } from './mcpServerTypes';
import { McpServerCard } from './McpServerCard';
import { McpServerFormDialog } from './McpServerFormDialog';
import { useMcpServers } from './useMcpServers';

interface Props {
  effectiveConfig?: Record<string, unknown> | null;
  onConfigSaved?: () => void;
}

export const McpServersSection = ({
  effectiveConfig,
  onConfigSaved,
}: Props) => {
  const { servers, config, section, actions, ui } = useMcpServers({
    effectiveConfig,
    onConfigSaved,
  });

  if (config.loading) return null;

  const {
    yamlServers,
    pureAdminServers,
    adminServers,
    statusMap,
    overriddenYamlIds,
    disabledIds,
  } = servers;

  const { hasChanges, totalTools, connectedCount, totalCount } = section;

  const {
    handleSave,
    handleReset,
    handleTestConnection,
    openAddDialog,
    openEditDialog,
    handleDialogSubmit,
    handleRemoveAdmin,
    handleToggleDisable,
    closeDialog,
    handleUrlChange,
    setDraft,
    setToast,
    clearTestResult,
  } = actions;

  const {
    draft,
    dialogOpen,
    toast,
    testResult,
    testing,
    urlError,
    isEditing,
    draftValid,
    showYamlOverrideInfo,
  } = ui;

  return (
    <>
      <AdminSection
        title="MCP Servers"
        description={
          totalCount > 0
            ? `${connectedCount}/${totalCount} connected · ${totalTools} tool${
                totalTools !== 1 ? 's' : ''
              } available`
            : 'Configure Model Context Protocol servers for tool use.'
        }
        source={config.source}
        saving={config.saving}
        error={config.error}
        onSave={handleSave}
        onReset={hasChanges ? handleReset : undefined}
      >
        {/* YAML Servers */}
        {yamlServers.length > 0 && (
          <Box sx={{ mb: 2 }}>
            <Typography
              variant="caption"
              sx={{
                fontWeight: 600,
                color: 'text.secondary',
                display: 'block',
                mb: 0.75,
                textTransform: 'uppercase',
                letterSpacing: '0.05em',
              }}
            >
              YAML Configured ({yamlServers.length})
            </Typography>
            {yamlServers.map((s: McpServer) => {
              const disabled = disabledIds.has(s.id);
              const overridden = overriddenYamlIds.has(s.id);
              const display = overridden
                ? (adminServers.find(a => a.id === s.id) ?? s)
                : s;
              return (
                <McpServerCard
                  key={s.id}
                  server={display}
                  statusInfo={disabled ? undefined : statusMap.get(s.id)}
                  isYaml
                  isOverridden={overridden}
                  isDisabled={disabled}
                  onEdit={() => openEditDialog(display)}
                  onDisable={() => handleToggleDisable(s.id)}
                />
              );
            })}
          </Box>
        )}

        {/* Admin-Added Servers */}
        <Box>
          <Typography
            variant="caption"
            sx={{
              fontWeight: 600,
              color: 'text.secondary',
              display: 'block',
              mb: 0.75,
              textTransform: 'uppercase',
              letterSpacing: '0.05em',
            }}
          >
            Admin Added ({pureAdminServers.length})
          </Typography>

          {pureAdminServers.length > 0 ? (
            pureAdminServers.map(s => (
              <McpServerCard
                key={s.id}
                server={s}
                statusInfo={statusMap.get(s.id)}
                isYaml={false}
                onEdit={() => openEditDialog(s)}
                onRemove={() => handleRemoveAdmin(s.id)}
              />
            ))
          ) : (
            <Typography
              variant="body2"
              color="textSecondary"
              sx={{ mb: 1, fontStyle: 'italic' }}
            >
              No additional servers. Click &quot;Add Server&quot; to add one.
            </Typography>
          )}
        </Box>

        <Button
          size="small"
          startIcon={<AddIcon />}
          onClick={openAddDialog}
          sx={{ mt: 1, textTransform: 'none' }}
        >
          Add Server
        </Button>
      </AdminSection>

      <McpServerFormDialog
        open={dialogOpen}
        onClose={closeDialog}
        draft={draft}
        setDraft={setDraft}
        isEditing={isEditing}
        testResult={testResult}
        testing={testing}
        onTestConnection={handleTestConnection}
        onUrlChange={handleUrlChange}
        onClearTestResult={clearTestResult}
        urlError={urlError}
        onSubmit={handleDialogSubmit}
        draftValid={draftValid}
        showYamlOverrideInfo={showYamlOverrideInfo}
      />

      <Snackbar
        open={!!toast}
        autoHideDuration={4000}
        onClose={() => setToast(null)}
        message={toast}
        anchorOrigin={{ vertical: 'bottom', horizontal: 'center' }}
      />
    </>
  );
};
