import { useMemo, useCallback } from 'react';
import { useTheme } from '@mui/material/styles';
import Box from '@mui/material/Box';
import Typography from '@mui/material/Typography';
import Button from '@mui/material/Button';
import Paper from '@mui/material/Paper';
import Chip from '@mui/material/Chip';
import Slider from '@mui/material/Slider';
import Tooltip from '@mui/material/Tooltip';
import IconButton from '@mui/material/IconButton';
import AccessTimeIcon from '@mui/icons-material/AccessTime';
import DownloadIcon from '@mui/icons-material/Download';
import type { RagTestResult } from '../../types';
import type { ActiveVectorStore } from '../../hooks';
import { ChunkCard } from './ChunkCard';
import { getScoreColor } from './ragResultsUtils';

const CHUNK_PREVIEW_LENGTH = 300;

export interface RagResultsTableProps {
  result: RagTestResult;
  searchTimeMs: number | null;
  searchAllStores: boolean;
  stores: ActiveVectorStore[];
  expandedChunks: Set<number>;
  onToggleChunk: (index: number) => void;
  onExpandCollapseAll: () => void;
  scoreThreshold: number;
  onScoreThresholdChange: (value: number) => void;
}

function ScoreStats({ chunks }: { chunks: RagTestResult['chunks'] }) {
  const theme = useTheme();
  const scores = chunks
    .map(c => c.score)
    .filter((s): s is number => s !== undefined);

  if (scores.length === 0) return null;

  const min = Math.min(...scores);
  const max = Math.max(...scores);
  const avg = scores.reduce((a, b) => a + b, 0) / scores.length;

  const items = [
    { label: 'Min', value: min },
    { label: 'Avg', value: avg },
    { label: 'Max', value: max },
  ];

  return (
    <Box
      sx={{
        display: 'flex',
        gap: 2.5,
        mb: 1,
        px: 0.5,
      }}
    >
      {items.map(item => (
        <Box
          key={item.label}
          sx={{ display: 'flex', alignItems: 'center', gap: 0.5 }}
        >
          <Typography
            variant="caption"
            color="textSecondary"
            sx={{ fontSize: '0.675rem' }}
          >
            {item.label}:
          </Typography>
          <Typography
            variant="caption"
            sx={{
              fontWeight: 600,
              color: getScoreColor(item.value, theme),
              fontVariantNumeric: 'tabular-nums',
              fontSize: '0.7rem',
            }}
          >
            {(item.value * 100).toFixed(1)}%
          </Typography>
        </Box>
      ))}
      <Box sx={{ display: 'flex', alignItems: 'center', gap: 0.5 }}>
        <Typography
          variant="caption"
          color="textSecondary"
          sx={{ fontSize: '0.675rem' }}
        >
          Spread:
        </Typography>
        <Box
          sx={{
            width: 48,
            height: 6,
            borderRadius: 3,
            bgcolor: 'grey.200',
            position: 'relative',
            overflow: 'hidden',
          }}
        >
          <Box
            sx={{
              position: 'absolute',
              left: `${min * 100}%`,
              width: `${(max - min) * 100}%`,
              height: '100%',
              borderRadius: 3,
              bgcolor: getScoreColor(avg, theme),
              minWidth: 2,
            }}
          />
        </Box>
      </Box>
    </Box>
  );
}

export function RagResultsTable({
  result,
  searchTimeMs,
  searchAllStores,
  stores,
  expandedChunks,
  onToggleChunk,
  onExpandCollapseAll,
  scoreThreshold,
  onScoreThresholdChange,
}: RagResultsTableProps) {
  const theme = useTheme();
  const storeNameMap = new Map(
    stores.map(s => [s.id, s.name !== s.id ? s.name : s.id]),
  );

  const chunks = useMemo(() => result.chunks ?? [], [result.chunks]);
  const longChunkIndices = chunks
    .map((c, i) => (c.text.length > CHUNK_PREVIEW_LENGTH ? i : -1))
    .filter(i => i >= 0);
  const allExpanded =
    longChunkIndices.length > 0 &&
    longChunkIndices.every(i => expandedChunks.has(i));

  const passingCount = useMemo(
    () =>
      scoreThreshold > 0
        ? chunks.filter(c => (c.score ?? 0) >= scoreThreshold).length
        : chunks.length,
    [chunks, scoreThreshold],
  );

  const handleExportJson = useCallback(() => {
    const exportData = {
      ...result,
      exportedAt: new Date().toISOString(),
      searchTimeMs,
    };
    const blob = new Blob([JSON.stringify(exportData, null, 2)], {
      type: 'application/json',
    });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `rag-test-${Date.now()}.json`;
    a.click();
    URL.revokeObjectURL(url);
  }, [result, searchTimeMs]);

  return (
    <Box>
      {/* Results summary header */}
      <Box
        sx={{
          display: 'flex',
          alignItems: 'center',
          justifyContent: 'space-between',
          mb: 1,
          px: 0.5,
        }}
      >
        <Typography variant="subtitle2" sx={{ fontWeight: 600 }}>
          {result.totalResults} result
          {result.totalResults !== 1 ? 's' : ''}
          {!searchAllStores && result.vectorStoreId && (
            <>
              {' '}
              from{' '}
              <Chip
                label={
                  storeNameMap.get(result.vectorStoreId) ?? result.vectorStoreId
                }
                size="small"
                variant="outlined"
                sx={{ fontSize: '0.7rem', height: 20, mx: 0.5 }}
              />
            </>
          )}
          {searchAllStores && <> across {stores.length} stores</>}
        </Typography>
        <Box sx={{ display: 'flex', alignItems: 'center', gap: 1 }}>
          {searchTimeMs !== null && (
            <Box
              sx={{
                display: 'flex',
                alignItems: 'center',
                gap: 0.5,
              }}
            >
              <AccessTimeIcon sx={{ fontSize: 14, color: 'text.disabled' }} />
              <Typography
                variant="caption"
                color="textSecondary"
                sx={{ fontVariantNumeric: 'tabular-nums' }}
              >
                {searchTimeMs < 1000
                  ? `${searchTimeMs}ms`
                  : `${(searchTimeMs / 1000).toFixed(2)}s`}
              </Typography>
            </Box>
          )}
          <Tooltip title="Export results as JSON">
            <IconButton size="small" onClick={handleExportJson}>
              <DownloadIcon sx={{ fontSize: 16 }} />
            </IconButton>
          </Tooltip>
        </Box>
      </Box>

      {/* No results guidance */}
      {chunks.length === 0 ? (
        <Paper
          variant="outlined"
          sx={{ p: 2.5, textAlign: 'center', borderStyle: 'dashed' }}
        >
          <Typography variant="body2" color="textSecondary" gutterBottom>
            No matching chunks found.
          </Typography>
          <Typography variant="caption" color="textSecondary" component="div">
            Try broader search terms, check that your documents cover this
            topic, or verify that files are properly ingested and chunked.
          </Typography>
        </Paper>
      ) : (
        <>
          {/* Score statistics */}
          <ScoreStats chunks={chunks} />

          {/* Score legend */}
          <Box
            sx={{
              display: 'flex',
              gap: 2,
              mb: 1,
              px: 0.5,
            }}
          >
            {[
              { label: 'High (\u226570%)', color: theme.palette.success.main },
              {
                label: 'Medium (40\u201370%)',
                color: theme.palette.warning.main,
              },
              { label: 'Low (<40%)', color: theme.palette.error.main },
            ].map(item => (
              <Box
                key={item.label}
                sx={{
                  display: 'flex',
                  alignItems: 'center',
                  gap: 0.5,
                }}
              >
                <Box
                  sx={{
                    width: 8,
                    height: 8,
                    borderRadius: '50%',
                    bgcolor: item.color,
                  }}
                />
                <Typography
                  variant="caption"
                  color="textSecondary"
                  sx={{ fontSize: '0.675rem' }}
                >
                  {item.label}
                </Typography>
              </Box>
            ))}
          </Box>

          {/* Score threshold slider */}
          <Box
            sx={{
              display: 'flex',
              alignItems: 'center',
              gap: 2,
              mb: 1.5,
              px: 0.5,
            }}
          >
            <Typography
              variant="caption"
              color="textSecondary"
              sx={{ whiteSpace: 'nowrap', fontSize: '0.75rem' }}
            >
              Score threshold:
            </Typography>
            <Slider
              size="small"
              value={scoreThreshold}
              onChange={(_, v) => onScoreThresholdChange(v as number)}
              min={0}
              max={1}
              step={0.05}
              valueLabelDisplay="auto"
              valueLabelFormat={v => `${(v * 100).toFixed(0)}%`}
              sx={{ flex: 1, maxWidth: 200 }}
            />
            <Typography
              variant="caption"
              sx={{
                fontWeight: 600,
                fontVariantNumeric: 'tabular-nums',
                minWidth: 36,
                fontSize: '0.75rem',
              }}
            >
              {(scoreThreshold * 100).toFixed(0)}%
            </Typography>
            {scoreThreshold > 0 && (
              <Chip
                label={`${passingCount} of ${chunks.length} pass`}
                size="small"
                color={passingCount === 0 ? 'error' : 'default'}
                variant="outlined"
                sx={{ fontSize: '0.675rem', height: 20 }}
              />
            )}
          </Box>

          {/* Chunk cards */}
          {chunks.map((chunk, i) => {
            const belowThreshold =
              scoreThreshold > 0 && (chunk.score ?? 0) < scoreThreshold;
            return (
              <Box
                key={i}
                sx={{
                  opacity: belowThreshold ? 0.35 : 1,
                  transition: 'opacity 0.2s ease',
                }}
              >
                <ChunkCard
                  chunk={chunk}
                  index={i}
                  query={result.query}
                  expanded={expandedChunks.has(i)}
                  onToggle={() => onToggleChunk(i)}
                  storeName={
                    chunk.vectorStoreId
                      ? storeNameMap.get(chunk.vectorStoreId)
                      : undefined
                  }
                  showStore={searchAllStores}
                  theme={theme}
                  belowThreshold={belowThreshold}
                />
              </Box>
            );
          })}

          {/* Expand/collapse all (when multiple long chunks) */}
          {longChunkIndices.length > 1 && (
            <Box sx={{ display: 'flex', justifyContent: 'center', mt: 0.5 }}>
              <Button
                size="small"
                onClick={onExpandCollapseAll}
                sx={{
                  textTransform: 'none',
                  fontSize: '0.75rem',
                  color: 'text.secondary',
                }}
              >
                {allExpanded ? 'Collapse all chunks' : 'Expand all chunks'}
              </Button>
            </Box>
          )}
        </>
      )}
    </Box>
  );
}
