import { useState, useRef, useCallback, useEffect } from 'react';
import { Message } from '../types';
import { debugLog, debugError } from '../utils';
import type { ChatContainerRef } from '../components/ChatContainer';

interface SessionMessageResult {
  messages: Array<{
    role: 'user' | 'assistant';
    text: string;
    createdAt?: string;
    toolCalls?: Array<{
      id: string;
      name: string;
      serverLabel: string;
      arguments?: string;
      output?: string;
      error?: string;
    }>;
    ragSources?: Array<{
      filename: string;
      text?: string;
      score?: number;
      fileId?: string;
      attributes?: Record<string, unknown>;
    }>;
  }>;
  sessionCreatedAt?: string;
  hasConversationId?: boolean;
}

export interface UseChatSessionsApi {
  getSessionMessages(sessionId: string): Promise<SessionMessageResult>;
  getAdminSessionMessages(sessionId: string): Promise<SessionMessageResult>;
}

export interface UseChatSessionsOptions {
  api: UseChatSessionsApi;
  chatContainerRef: React.RefObject<ChatContainerRef | null>;
  isStreaming?: boolean;
}

export interface UseChatSessionsReturn {
  // State
  activeSessionId: string | undefined;
  messages: Message[];
  loadingConversation: boolean;
  /** True when a session had a linked conversation but its messages could not be loaded */
  messagesUnavailable: boolean;
  sessionRefreshTrigger: number;
  switchDialogOpen: boolean;
  error: string | null;
  setError: (error: string | null) => void;

  // Handlers
  handleNewChat: () => void;
  handleMessagesChange: (newMessages: Message[]) => void;
  handleSessionCreated: (newSessionId: string) => void;
  handleSelectSession: (
    sessionId: string,
    adminView?: boolean,
    sessionModel?: string,
  ) => Promise<void>;
  guardedSelectSession: (sessionId: string, adminView?: boolean, sessionModel?: string) => void;
  handleSwitchConfirm: () => void;
  handleSwitchCancel: () => void;
}

export function useChatSessions({
  api,
  chatContainerRef,
  isStreaming,
}: UseChatSessionsOptions): UseChatSessionsReturn {
  const [messages, setMessages] = useState<Message[]>([]);
  const [activeSessionId, setActiveSessionId] = useState<string | undefined>();
  const [loadingConversation, setLoadingConversation] = useState(false);
  const [messagesUnavailable, setMessagesUnavailable] = useState(false);
  const [sessionRefreshTrigger, setSessionRefreshTrigger] = useState(0);
  const [switchDialogOpen, setSwitchDialogOpen] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const loadAbortRef = useRef<AbortController | null>(null);
  const pendingSwitchRef = useRef<{
    sessionId: string;
    adminView?: boolean;
    sessionModel?: string;
  } | null>(null);

  // Cancel any in-flight conversation load on unmount
  useEffect(() => {
    return () => {
      loadAbortRef.current?.abort();
    };
  }, []);

  const handleNewChat = useCallback(() => {
    loadAbortRef.current?.abort();
    if (chatContainerRef.current) {
      chatContainerRef.current.cancelOngoingRequest();
      chatContainerRef.current.resetConversation();
      chatContainerRef.current.clearInput();
      chatContainerRef.current.setSelectedModel(undefined);
    }
    setError(null);
    setMessages([]);
    setActiveSessionId(undefined);
    setLoadingConversation(false);
    setMessagesUnavailable(false);
  }, [chatContainerRef]);

  const refreshDebounceRef = useRef<ReturnType<typeof setTimeout> | null>(null);

  const handleMessagesChange = useCallback((newMessages: Message[]) => {
    setMessages(newMessages);
    if (refreshDebounceRef.current) clearTimeout(refreshDebounceRef.current);
    refreshDebounceRef.current = setTimeout(() => {
      setSessionRefreshTrigger(prev => prev + 1);
    }, 500);
  }, []);

  useEffect(() => {
    return () => {
      if (refreshDebounceRef.current) clearTimeout(refreshDebounceRef.current);
    };
  }, []);

  const handleSessionCreated = useCallback((newSessionId: string) => {
    setActiveSessionId(newSessionId);
  }, []);

  const handleSelectSession = useCallback(
    async (sessionId: string, adminView?: boolean, sessionModel?: string) => {
      if (loadAbortRef.current) {
        loadAbortRef.current.abort();
      }
      chatContainerRef.current?.cancelOngoingRequest();
      chatContainerRef.current?.clearInput();

      const abortController = new AbortController();
      loadAbortRef.current = abortController;

      setLoadingConversation(true);
      setMessagesUnavailable(false);

      try {
        debugLog('Loading session:', sessionId, adminView ? '(admin)' : '');

        const result = adminView
          ? await api.getAdminSessionMessages(sessionId)
          : await api.getSessionMessages(sessionId);
        if (abortController.signal.aborted) return;

        const {
          messages: processed,
          sessionCreatedAt,
          hasConversationId,
        } = result;
        const fallbackBase = sessionCreatedAt
          ? new Date(sessionCreatedAt)
          : new Date();
        const restoredMessages: Message[] = processed.map((pm, i) => {
          let timestamp: Date;
          if (pm.createdAt) {
            timestamp = new Date(pm.createdAt);
          } else {
            timestamp = new Date(fallbackBase.getTime() + i * 1000);
          }
          const msg: Message = {
            id: `restored-${i}`,
            text: pm.text,
            isUser: pm.role === 'user',
            timestamp,
          };
          if (pm.toolCalls && pm.toolCalls.length > 0) {
            msg.toolCalls = pm.toolCalls.map(tc => ({
              id: tc.id,
              name: tc.name,
              serverLabel: tc.serverLabel,
              arguments: tc.arguments || '{}',
              output: tc.output,
              error: tc.error,
            }));
          }
          if (pm.ragSources && pm.ragSources.length > 0) {
            msg.ragSources = pm.ragSources.map(rs => ({
              filename: rs.filename,
              text: rs.text ?? '',
              score: rs.score,
              fileId: rs.fileId,
              attributes: rs.attributes,
            }));
          }
          const pmAny = pm as Record<string, unknown>;
          if (pmAny.agentName) msg.agentName = pmAny.agentName as string;
          if (pmAny.reasoning) msg.reasoning = pmAny.reasoning as string;
          return msg;
        });

        debugLog(
          `Restored ${restoredMessages.length} messages (${
            restoredMessages.filter(m => m.isUser).length
          } user, ${restoredMessages.filter(m => !m.isUser).length} assistant)`,
        );

        setMessages(restoredMessages);
        setActiveSessionId(sessionId);
        setError(null);
        setMessagesUnavailable(
          restoredMessages.length === 0 && hasConversationId === true,
        );
        chatContainerRef.current?.setPreviousResponseId(undefined);
        chatContainerRef.current?.setConversationId(undefined);
        chatContainerRef.current?.setSessionId(sessionId);
        chatContainerRef.current?.setSelectedModel(sessionModel);
      } catch (err) {
        if (abortController.signal.aborted) return;
        debugError('Failed to load session:', err);
        setError(
          err instanceof Error
            ? `Failed to load session: ${err.message}`
            : 'Failed to load session',
        );
        setMessages([]);
        setActiveSessionId(undefined);
        setMessagesUnavailable(false);
      } finally {
        if (!abortController.signal.aborted) {
          setLoadingConversation(false);
        }
      }
    },
    [api, chatContainerRef],
  );

  const guardedSelectSession = useCallback(
    (sessionId: string, adminView?: boolean, sessionModel?: string) => {
      const streaming =
        typeof isStreaming === 'boolean'
          ? isStreaming
          : (chatContainerRef.current?.isStreaming() ?? false);
      if (streaming) {
        pendingSwitchRef.current = { sessionId, adminView, sessionModel };
        setSwitchDialogOpen(true);
        return;
      }
      handleSelectSession(sessionId, adminView, sessionModel);
    },
    [handleSelectSession, isStreaming, chatContainerRef],
  );

  const handleSwitchConfirm = useCallback(() => {
    setSwitchDialogOpen(false);
    chatContainerRef.current?.cancelOngoingRequest();
    chatContainerRef.current?.resetConversation();
    chatContainerRef.current?.clearInput();
    if (pendingSwitchRef.current) {
      const { sessionId, adminView, sessionModel } = pendingSwitchRef.current;
      pendingSwitchRef.current = null;
      handleSelectSession(sessionId, adminView, sessionModel);
    }
  }, [handleSelectSession, chatContainerRef]);

  const handleSwitchCancel = useCallback(() => {
    setSwitchDialogOpen(false);
    pendingSwitchRef.current = null;
  }, []);

  return {
    activeSessionId,
    messages,
    loadingConversation,
    messagesUnavailable,
    sessionRefreshTrigger,
    switchDialogOpen,
    error,
    setError,
    handleNewChat,
    handleMessagesChange,
    handleSessionCreated,
    handleSelectSession,
    guardedSelectSession,
    handleSwitchConfirm,
    handleSwitchCancel,
  };
}
