const rtf = new Intl.RelativeTimeFormat('en', { numeric: 'auto' });

const SECOND = 1000;
const MINUTE = 60 * SECOND;
const HOUR = 60 * MINUTE;
const DAY = 24 * HOUR;

/**
 * Format a Date as a human-friendly relative timestamp.
 * Returns "just now", "2 min ago", "1 hr ago", etc.
 * Falls back to absolute time (e.g. "11:30 AM") for messages older than 24 hours.
 */
export function formatRelativeTime(date: Date): string {
  const diff = Date.now() - date.getTime();

  if (diff < MINUTE) {
    return 'just now';
  }
  if (diff < HOUR) {
    return rtf.format(-Math.floor(diff / MINUTE), 'minute');
  }
  if (diff < DAY) {
    return rtf.format(-Math.floor(diff / HOUR), 'hour');
  }

  return date.toLocaleTimeString([], {
    hour: '2-digit',
    minute: '2-digit',
    month: 'short',
    day: 'numeric',
  });
}
