/**
 * Severity levels for tool approval based on operation type
 */
export type ToolSeverity = 'info' | 'warning' | 'critical';

/**
 * Determine severity based on tool name patterns
 */
export function getSeverity(toolName: string): ToolSeverity {
  const criticalPatterns = ['delete', 'remove', 'destroy', 'terminate', 'drop'];
  const warningPatterns = [
    'update',
    'modify',
    'patch',
    'scale',
    'restart',
    'create',
  ];
  const lowerName = toolName.toLowerCase();

  if (criticalPatterns.some(p => lowerName.includes(p))) {
    return 'critical';
  }
  if (warningPatterns.some(p => lowerName.includes(p))) {
    return 'warning';
  }
  return 'info';
}
